  // Terms of Service Page
  "terms.title": { fr: "Conditions d'Utilisation", en: "Terms of Service", ar: "شروط الاستخدام" },
  "terms.last_updated": { fr: "Dernière mise à jour", en: "Last updated", ar: "آخر تحديث" },
  "terms.agreement.title": { fr: "Acceptation des Conditions", en: "Agreement to Terms", ar: "الموافقة على الشروط" },
  "terms.agreement.content": { fr: "En accédant ou en utilisant les services fournis par Game Store Zarzis (« nous », « notre »), vous acceptez d'être lié par ces Conditions d'Utilisation. Si vous n'acceptez pas ces conditions, veuillez ne pas utiliser nos services.", en: "By accessing or using the services provided by Game Store Zarzis (\"we,\" \"us,\" or \"our\"), you agree to be bound by these Terms of Service. If you do not agree to these terms, please do not use our services.", ar: "باستخدام الخدمات المقدمة من Game Store Zarzis (\"نحن\")، فإنك توافق على الالتزام بشروط الاستخدام هذه. إذا كنت لا توافق على هذه الشروط، يرجى عدم استخدام خدماتنا." },
  "terms.gaming_rules.title": { fr: "Règles de la Zone Gaming", en: "Gaming Lounge Rules", ar: "قواعد منطقة الألعاب" },
  "terms.gaming_rules.rule1": { fr: "Respectez les autres joueurs et le personnel en tout temps.", en: "Respect other players and staff members at all times.", ar: "احترم اللاعبين الآخرين والموظفين في جميع الأوقات." },
  "terms.gaming_rules.rule2": { fr: "Les dommages causés aux équipements par une mauvaise utilisation seront facturés au client.", en: "Equipment damage caused by misuse will be charged to the client.", ar: "الأضرار التي تلحق بالمعدات بسبب سوء الاستخدام ستُحمّل على العميل." },
  "terms.gaming_rules.rule3": { fr: "Pas de nourriture ni de boissons près des consoles.", en: "No food or drink near the gaming consoles.", ar: "لا طعام أو شراب بالقرب من أجهزة الألعاب." },
  "terms.gaming_rules.rule4": { fr: "Le temps de session s'arrête uniquement lorsque vous informez le personnel.", en: "Session time stops only when you notify the staff.", ar: "وقت الجلسة يتوقف فقط عندما تُبلغ الموظفين." },
  "terms.gaming_rules.rule5": { fr: "Nous nous réservons le droit de refuser le service à toute personne violant ces règles.", en: "We reserve the right to refuse service to anyone violating these rules.", ar: "نحتفظ بالحق في رفض تقديم الخدمة لأي شخص ينتهك هذه القواعد." },
  "terms.account.title": { fr: "Compte & Points", en: "Account & Points", ar: "الحساب والنقاط" },
  "terms.account.rule1": { fr: "Les points de fidélité ne sont pas transférables et n'ont aucune valeur monétaire.", en: "Loyalty points are non-transferable and have no cash value.", ar: "نقاط الولاء غير قابلة للتحويل وليس لها قيمة نقدية." },
  "terms.account.rule2": { fr: "Nous nous réservons le droit de corriger les soldes de points en cas d'erreurs système.", en: "We reserve the right to correct point balances in case of system errors.", ar: "نحتفظ بالحق في تصحيح رصيد النقاط في حالة حدوث أخطاء في النظام." },
  "terms.account.rule3": { fr: "Les comptes inactifs depuis plus de 12 mois peuvent être archivés.", en: "Accounts inactive for more than 12 months may be archived.", ar: "قد يتم أرشفة الحسابات غير النشطة لأكثر من 12 شهراً." },
  "terms.account.rule4": { fr: "Vous êtes responsable de la confidentialité de vos informations de compte.", en: "You are responsible for maintaining the confidentiality of your account details.", ar: "أنت مسؤول عن الحفاظ على سرية تفاصيل حسابك." },
  "terms.services.title": { fr: "Services & Réparations", en: "Services & Repairs", ar: "الخدمات والإصلاحات" },
  "terms.services.warranty_label": { fr: "Garantie", en: "Warranty", ar: "الضمان" },
  "terms.services.warranty_text": { fr: "Toutes les réparations sont garanties 30 jours, couvrant la réparation effectuée et les pièces remplacées. Cette garantie ne couvre pas les dommages physiques ou les dégâts d'eau survenus après la réparation.", en: "All repairs come with a 30-day warranty covering the specific repair performed and parts replaced. This warranty does not cover physical damage or water damage occurring after the repair.", ar: "جميع الإصلاحات تأتي مع ضمان 30 يوماً يغطي الإصلاح المحدد الذي تم إجراؤه والقطع المستبدلة. لا يغطي هذا الضمان الأضرار المادية أو أضرار المياه التي تحدث بعد الإصلاح." },
  "terms.services.data_label": { fr: "Confidentialité des Données", en: "Data Privacy", ar: "خصوصية البيانات" },
  "terms.services.data_text": { fr: "Bien que nous prenions toutes les précautions pour protéger vos données, nous vous recommandons de sauvegarder votre appareil avant de le soumettre pour réparation. Nous ne sommes pas responsables de la perte de données.", en: "While we take every precaution to protect your data, we recommend backing up your device before submitting it for repair. We are not responsible for data loss.", ar: "بينما نتخذ كل الاحتياطات لحماية بياناتك، نوصي بعمل نسخة احتياطية لجهازك قبل تقديمه للإصلاح. نحن غير مسؤولين عن فقدان البيانات." },
  "terms.services.unclaimed_label": { fr: "Appareils Non Réclamés", en: "Unclaimed Devices", ar: "الأجهزة غير المُستلمة" },
  "terms.services.unclaimed_text": { fr: "Les appareils laissés plus de 90 jours après notification de fin de réparation peuvent être vendus pour récupérer les coûts.", en: "Devices left for more than 90 days after repair completion notification may be disposed of to recover costs.", ar: "الأجهزة المتروكة لأكثر من 90 يوماً بعد إشعار إتمام الإصلاح قد يتم التصرف فيها لاسترداد التكاليف." },
  "terms.contact.title": { fr: "Contactez-nous", en: "Contact Us", ar: "اتصل بنا" },
  "terms.contact.question": { fr: "Des questions sur ces conditions ?", en: "Have questions about these terms?", ar: "هل لديك أسئلة حول هذه الشروط؟" },
  "terms.contact.visit": { fr: "Visitez notre magasin à Zarzis ou contactez-nous par téléphone.", en: "Visit our store in Zarzis or contact us via phone.", ar: "قم بزيارة متجرنا في جرجيس أو اتصل بنا عبر الهاتف." },

